%加载数据
load data.mat

%计算实际采样频率
fs = 1/((data(2,1)-data(1,1))/1000);

%计算锁相放大器时间常数
tau = 1/(2*pi*1); %1Hz的频率

%计算窗口函数
N = length(data(:,1));
w = hann(N); %汉宁窗

%提取电流信号并加上脉冲电流激励
Is = data(:,3) + 0.25.*(square(2*pi*1.*data(:,1)/1000,50)+1).*4.125; 

%去除直流分量
Is = Is - mean(Is);

%FFT计算电流信号的频谱
Y = fft(w.*Is);
L = length(Y);
P2 = abs(Y/L);
P1 = P2(1:L/2+1);
P1(2:end-1) = 2*P1(2:end-1);
f = fs*(0:(L/2))/L;

%计算电化学阻抗
Z = P1(find(abs(f-1)<=fs/N))/0.25;

%画出奈奎斯特图
plot(real(Z),-imag(Z)); 
xlabel('Real(Z)')
ylabel('-Imag(Z)')

